module top_module(
    input clk,
    input rst,
    output reg [2:0] out
);reg [2:0] obf_count;

always @(posedge clk) begin
    if (rst) begin
        obf_count <= 3'b0;
    end else if (obf_count == 3'b111) begin
        obf_count <= 3'b0;
    end else begin
        obf_count <= obf_count + 1;
    end
end

assign out = obf_count;

endmodule
